import anthropic
import json
from datetime import datetime, timedelta

client = anthropic.Anthropic()

# Tools the agent can use
tools = [
    {
        "name": "fetch_github_prs",
        "description": "Fetch merged pull requests for a repository in a date range",
        "input_schema": {
            "type": "object",
            "properties": {
                "repo": {"type": "string"},
                "since": {"type": "string", "description": "ISO 8601 date"},
                "until": {"type": "string", "description": "ISO 8601 date"},
            },
            "required": ["repo", "since", "until"],
        },
    },
    {
        "name": "send_slack_message",
        "description": "Send a message to a Slack channel",
        "input_schema": {
            "type": "object",
            "properties": {
                "channel": {"type": "string"},
                "text": {"type": "string"},
            },
            "required": ["channel", "text"],
        },
    },
]

def dispatch(tool_name: str, tool_input: dict) -> str:
    if tool_name == "fetch_github_prs":
        # Real implementation: call GitHub API
        return json.dumps([
            {"number": 142, "title": "Add OAuth2 support", "author": "alice", "merged_at": "2026-07-01T10:00:00Z"},
            {"number": 143, "title": "Fix null pointer in payment flow", "author": "bob", "merged_at": "2026-07-01T14:30:00Z"},
        ])
    elif tool_name == "send_slack_message":
        # Real implementation: call Slack API
        print(f"[Slack #{tool_input['channel']}] {tool_input['text'][:80]}...")
        return json.dumps({"ok": True})
    return json.dumps({"error": "unknown tool"})

def run_weekly_digest_agent(repo: str, slack_channel: str) -> None:
    """Background agent: runs on a cron schedule, no user interaction."""
    today = datetime.utcnow()
    week_ago = today - timedelta(days=7)

    messages = [{
        "role": "user",
        "content": (
            f"Generate a weekly digest for the {repo} repository. "
            f"Fetch PRs merged between {week_ago.date().isoformat()} and {today.date().isoformat()}, "
            f"summarise them in a Slack-friendly format (bullet points, @mentions for authors), "
            f"and send to #{slack_channel}."
        ),
    }]

    while True:
        response = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            print("Digest agent completed successfully")
            break

        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = dispatch(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})

# Called by a cron job or scheduler
if __name__ == "__main__":
    run_weekly_digest_agent(repo="acme/backend", slack_channel="engineering-digest")

