# Example: automatically triage new GitHub issues

from fastapi import FastAPI, Request
import anthropic, json, httpx

app = FastAPI()
client = anthropic.Anthropic()

TRIAGE_TOOLS = [
    {
        "name": "search_similar_issues",
        "description": "Search for similar existing issues in the repo",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "limit": {"type": "integer", "default": 5},
            },
            "required": ["query"],
        },
    },
    {
        "name": "add_labels",
        "description": "Add labels to a GitHub issue",
        "input_schema": {
            "type": "object",
            "properties": {
                "issue_number": {"type": "integer"},
                "labels": {"type": "array", "items": {"type": "string"}},
            },
            "required": ["issue_number", "labels"],
        },
    },
    {
        "name": "add_comment",
        "description": "Add a comment to a GitHub issue",
        "input_schema": {
            "type": "object",
            "properties": {
                "issue_number": {"type": "integer"},
                "body": {"type": "string"},
            },
            "required": ["issue_number", "body"],
        },
    },
]

@app.post("/webhook/github")
async def handle_github_webhook(request: Request):
    payload = await request.json()
    if payload.get("action") != "opened":
        return {"status": "ignored"}

    issue = payload["issue"]
    # Run the triage agent in the background — don't block the webhook response
    import asyncio
    asyncio.create_task(triage_issue(issue))
    return {"status": "accepted"}

async def triage_issue(issue: dict) -> None:
    """Background agent: triggered by webhook, runs asynchronously."""
    messages = [{
        "role": "user",
        "content": (
            f"Triage this new GitHub issue:\n"
            f"Title: {issue['title']}\n"
            f"Body: {issue['body']}\n\n"
            f"Search for similar issues, assign appropriate labels "
            f"(bug/enhancement/question/documentation), and leave a "
            f"welcoming comment acknowledging the report."
        ),
    }]

    while True:
        response = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=1024,
            tools=TRIAGE_TOOLS,
            messages=messages,
        )
        if response.stop_reason == "end_turn":
            break
        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
